const { Pool } = require('pg');
const express = require('express');
const app = express();
app.use(express.json());

const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
  ssl: { rejectUnauthorized: false }
});

app.get('/table/:tableName', async (req, res) => {
  try {
    const { tableName } = req.params;
    const result = await pool.query(`SELECT * FROM ${tableName}`);
    res.json(result.rows);
  } catch (err) {
    res.status(500).send(err.message);
  }
});

app.post('/table/:tableName', async (req, res) => {
  try {
    const { tableName } = req.params;
    const { columns, values } = req.body;
    const result = await pool.query(`INSERT INTO ${tableName} (${columns.join(', ')}) VALUES (${values.map((_, i) => `$${i + 1}`).join(', ')}) RETURNING *`, values);
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).send(err.message);
  }
});

app.put('/table/:tableName/:id', async (req, res) => {
  try {
    const { tableName, id } = req.params;
    const { columns, values } = req.body;
    const setClause = columns.map((col, i) => `${col} = $${i + 1}`).join(', ');
    const result = await pool.query(`UPDATE ${tableName} SET ${setClause} WHERE id = $${columns.length + 1} RETURNING *`, [...values, id]);
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).send(err.message);
  }
});

app.delete('/table/:tableName/:id', async (req, res) => {
  try {
    const { tableName, id } = req.params;
    await pool.query(`DELETE FROM ${tableName} WHERE id = $1`, [id]);
    res.sendStatus(204);
  } catch (err) {
    res.status(500).send(err.message);
  }
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});